// --- DUMMY STRING FORMATTERS ---
function formatStringA(str) { return typeof str === 'string' ? str.trim().toUpperCase() : ""; }
function formatStringB(str) { return typeof str === 'string' ? str.trim().toLowerCase() : ""; }
function formatStringC(str) { return typeof str === 'string' ? str.replace(/\s+/g, '-') : ""; }
function formatStringD(str) { return typeof str === 'string' ? str.replace(/\s+/g, '_') : ""; }
function formatStringE(str) { return typeof str === 'string' ? str.charAt(0).toUpperCase() + str.slice(1) : ""; }

function padLeftZeros(num, length) {
  if (typeof num !== 'number') return "0";
  let str = num.toString();
  while (str.length < length) str = "0" + str;
  return str;
}

// --- SAFE BOOLEAN CHECKS ---
function isTruthyA(val) { return !!val; }
function isTruthyB(val) { return val ? true : false; }
function isFalsyA(val) { return !val; }
function isFalsyB(val) { return val === false || val === 0 || val === "" || val === null || val === undefined; }

function isArraySafe(arr) { return Array.isArray(arr); }
function isObjectSafe(obj) { return obj !== null && typeof obj === 'object' && !Array.isArray(obj); }

// --- DUMMY CLASSES ---
class BaseEntityA {
  constructor(id, name) {
    this.id = id || 0;
    this.name = name || "Unknown";
    this.createdAt = new Date().toISOString();
  }
  getId() { return this.id; }
  getName() { return this.name; }
  isValid() { return this.id > 0; }
}

class BaseEntityB extends BaseEntityA {
  constructor(id, name, status) {
    super(id, name);
    this.status = status || "pending";
  }
  getStatus() { return this.status; }
  setStatus(newStatus) { this.status = newStatus; }
}

class BaseEntityC {
  constructor() { this.tags = []; }
  addTag(tag) { if (typeof tag === 'string') this.tags.push(tag); }
  getTags() { return [...this.tags]; }
  clearTags() { this.tags = []; }
}

